import React, { useEffect, useState } from "react";
import { Table, Button, Space, Input, Tooltip } from "antd";
import {
  Edit3,
  Trash2,
  Search,
  Plus,
  Palette,
  Activity,
  ShieldCheck,
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import {
  deleteAColor,
  getColors,
  resetState,
} from "../features/color/colorSlice";
import CustomModal from "../components/CustomModal";

const Colorlist = () => {
  const [open, setOpen] = useState(false);
  const [colorId, setcolorId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setcolorId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(resetState());
    dispatch(getColors());
  }, [dispatch]);

  const colorState = useSelector((state) => state.color.colors);

  const columns = [
    {
      title: "#",
      dataIndex: "key",
      width: 80,
      render: (text) => (
        <span className="font-mono text-[10px] font-black text-slate-400 bg-slate-50 px-2 py-1 rounded-md">
          CLR-{text}
        </span>
      ),
    },
    {
      title: "COLOR",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-3">
          <Tooltip title={text}>
            <div
              className="w-8 h-8 rounded-xl border-2 border-white shadow-md ring-1 ring-slate-100"
              style={{ backgroundColor: text }}
            />
          </Tooltip>
          <span className="font-black text-slate-900 tracking-tight uppercase text-xs">
            {text}
          </span>
        </div>
      ),
      sorter: (a, b) => a.name.length - b.name.length,
    },
    {
      title: "ACTIONS",
      dataIndex: "action",
      render: (_, record) => (
        <Space size="middle">
          <Link to={`../color/${record._id}`}>
            <Button
              type="text"
              icon={<Edit3 size={16} />}
              className="text-slate-400 hover:text-blue-600 rounded-xl"
            />
          </Link>
          <Button
            type="text"
            danger
            icon={<Trash2 size={16} />}
            onClick={() => showModal(record._id)}
            className="rounded-xl"
          />
        </Space>
      ),
    },
  ];

  const data1 =
    colorState
      ?.filter(
        (c) =>
          !searchText ||
          c.title.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((color, i) => ({
        key: i + 1,
        _id: color._id,
        name: color.title,
      })) || [];

  const deleteColor = (e) => {
    dispatch(deleteAColor(e));
    setOpen(false);
    setTimeout(() => {
      dispatch(getColors());
    }, 100);
  };

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Palette size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              Color Registry
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <ShieldCheck size={12} /> {data1.length} Colors
            </span>
            <span className="flex items-center gap-2 text-[10px] font-black text-emerald-600 bg-emerald-50 border border-emerald-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Activity size={12} /> System Active
            </span>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
          <div className="relative">
            <Search
              className="absolute top-1/2 left-4 -translate-y-1/2 text-slate-300"
              size={16}
            />
            <Input
              placeholder="Search colors..."
              className="pl-11 rounded-2xl border-slate-100 w-64 h-11 font-medium text-xs"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <Link to="../color">
            <Button
              type="primary"
              size="large"
              icon={<Plus size={16} />}
              className="bg-[#257CB7] rounded-2xl h-11 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none flex items-center gap-2"
            >
              Add Color
            </Button>
          </Link>
        </div>
      </div>

      <div className="enterprise-card bg-white p-4 border-none shadow-2xl shadow-slate-200/40">
        <Table
          columns={columns}
          dataSource={data1}
          pagination={{ pageSize: 12 }}
          className="enterprise-table"
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteColor(colorId)}
        title="Confirm Color Deletion"
        content="This will remove the color. Products with this color attribute may need updating."
      />
    </div>
  );
};

export default Colorlist;
